import React, { useEffect, useState } from 'react';
import AppLayout from '../../components/shared/AppLayout';
import LoadingSpinner from '../../components/shared/LoadingSpinner';
import api from '../../utils/api';
import toast from 'react-hot-toast';

const emptyForm = { name: '', description: '', image: '' };

export default function AdminCharities() {
  const [charities, setCharities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState(emptyForm);
  const [editing, setEditing] = useState(null);
  const [saving, setSaving] = useState(false);
  const [showForm, setShowForm] = useState(false);

  const fetchCharities = () => {
    api.get('/charities')
      .then(r => setCharities(r.data.charities))
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetchCharities(); }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name || !form.description) return toast.error('Name and description required');
    setSaving(true);
    try {
      if (editing) {
        await api.put(`/charities/${editing}`, form);
        toast.success('Charity updated');
      } else {
        await api.post('/charities', form);
        toast.success('Charity created! 💚');
      }
      fetchCharities();
      setForm(emptyForm);
      setEditing(null);
      setShowForm(false);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save');
    } finally {
      setSaving(false);
    }
  };

  const startEdit = (c) => {
    setForm({ name: c.name, description: c.description, image: c.image || '' });
    setEditing(c._id);
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Deactivate this charity? It will be hidden from users.')) return;
    try {
      await api.delete(`/charities/${id}`);
      setCharities(p => p.filter(c => c._id !== id));
      toast.success('Charity deactivated');
    } catch {
      toast.error('Failed to deactivate');
    }
  };

  const cancelEdit = () => {
    setForm(emptyForm);
    setEditing(null);
    setShowForm(false);
  };

  return (
    <AppLayout>
      <div className="max-w-5xl mx-auto space-y-6 animate-slide-up">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="page-title">Charities</h1>
            <p className="text-charcoal-400 mt-1">Manage the charities users can support</p>
          </div>
          <button
            onClick={() => { setShowForm(p => !p); if (editing) cancelEdit(); }}
            className="btn-primary"
          >
            {showForm && !editing ? '✕ Cancel' : '+ Add Charity'}
          </button>
        </div>

        {/* Form */}
        {showForm && (
          <div className="card border border-forest-800/40 animate-slide-up">
            <h2 className="section-title mb-5">{editing ? 'Edit Charity' : 'New Charity'}</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className="label">Charity Name *</label>
                  <input
                    type="text"
                    className="input-field"
                    placeholder="e.g. Red Cross"
                    value={form.name}
                    onChange={e => setForm(p => ({ ...p, name: e.target.value }))}
                    required
                  />
                </div>
                <div>
                  <label className="label">Image URL</label>
                  <input
                    type="url"
                    className="input-field"
                    placeholder="https://..."
                    value={form.image}
                    onChange={e => setForm(p => ({ ...p, image: e.target.value }))}
                  />
                </div>
              </div>
              <div>
                <label className="label">Description *</label>
                <textarea
                  className="input-field resize-none"
                  rows={3}
                  placeholder="Describe the charity's mission..."
                  value={form.description}
                  onChange={e => setForm(p => ({ ...p, description: e.target.value }))}
                  required
                />
              </div>

              {/* Image preview */}
              {form.image && (
                <div className="flex items-center gap-3">
                  <img
                    src={form.image}
                    alt="Preview"
                    className="w-16 h-16 rounded-xl object-cover border border-charcoal-700"
                    onError={e => e.target.style.display = 'none'}
                  />
                  <span className="text-xs text-charcoal-500">Image preview</span>
                </div>
              )}

              <div className="flex gap-3">
                <button type="submit" className="btn-primary" disabled={saving}>
                  {saving ? 'Saving...' : editing ? 'Update Charity' : 'Create Charity'}
                </button>
                {editing && (
                  <button type="button" onClick={cancelEdit} className="btn-outline">
                    Cancel
                  </button>
                )}
              </div>
            </form>
          </div>
        )}

        {/* Charities grid */}
        {loading ? (
          <div className="flex justify-center py-12"><LoadingSpinner size="lg" /></div>
        ) : charities.length === 0 ? (
          <div className="card text-center py-16">
            <div className="text-5xl mb-4">💚</div>
            <p className="text-charcoal-300 font-medium">No charities yet</p>
            <p className="text-charcoal-500 text-sm mt-1">Add the first charity using the button above</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
            {charities.map(c => (
              <div key={c._id} className="card group">
                {/* Image */}
                <div className="h-36 rounded-xl overflow-hidden bg-charcoal-800 mb-4">
                  {c.image ? (
                    <img
                      src={c.image}
                      alt={c.name}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                    />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center text-4xl">💚</div>
                  )}
                </div>

                <h3 className="font-display font-semibold text-white mb-2 leading-snug">{c.name}</h3>
                <p className="text-xs text-charcoal-500 leading-relaxed mb-4 line-clamp-2">{c.description}</p>

                <div className="flex gap-2 mt-auto">
                  <button
                    onClick={() => startEdit(c)}
                    className="flex-1 text-xs text-center py-2 rounded-lg border border-charcoal-700 text-charcoal-400 hover:border-forest-700 hover:text-forest-400 transition-all font-medium"
                  >
                    ✏️ Edit
                  </button>
                  <button
                    onClick={() => handleDelete(c._id)}
                    className="flex-1 text-xs text-center py-2 rounded-lg border border-red-900/40 text-red-500 hover:bg-red-900/20 transition-all font-medium"
                  >
                    🗑 Remove
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </AppLayout>
  );
}
